#pragma once
#include "gdal.h"
#include "gdal_priv.h"
#include "cpl_conv.h"
#include<omp.h>
#include "RtA4HexDGGS.h"
#include "tifrpcdataset.h"
#include "rpcsensormodel.h"
#include "georaster.h"

/*
 * @brief	 Image quality assessment based on local metrics.
 *
 * @param originImage: The path of the original image.
 * @param HexDirec: The path of the orthophotograph generated by the proposed method.
 * @param HexIndir: The path of the orthophotograph generated by the traditional method.
 * @param rpbexFile: The path of the extended rpbex file.
 * @param demFile: The path of the digital elevation model (DEM) file.
 * @param prjexFile: The path of the extended projection file.
 *
 * @return	 A double-type array containing 6 values,
			 which respectively represent the mean absolute error(MAE), mean square error(MSE),
			 and structural similarity index measure(SSIM) of the proposed method and the traditional method.
 */
double* localQA(const std::string,
	const std::string,
	const std::string,
	const std::string,
	const std::string,
	const std::string);

/*
 * @brief	 Image quality assessment based on global metrics.
 *
 * @param srcImagePath: The path of the original image.
 * @param HexDirec: The path of the orthophotograph generated by the proposed method.
 * @param HexIndir: The path of the orthophotograph generated by the traditional method.
 *
 * @return	 A double-type array containing 6 values,
			 which respectively represent the mean, standard deviation, and average gradient
			 of the proposed method and the traditional method relative to the original image.
 */
double* globalQA(const std::string,
	const std::string,
	const std::string);